parameters.jsCode:
const body = $json.body || $json;

const service = body.service || body.name || body.project || 'Unknown Service';
const status = body.status || body.state || 'deployed';
const version = body.version || body.tag || body.commit || '';
const environment = body.environment || body.env || 'production';
const actor = body.actor || body.user || body.triggered_by || 'System';
const url = body.url || body.domain || '';

const isSuccess = ['deployed', 'success', 'running', 'healthy'].includes(status.toLowerCase());
const isFailed = ['failed', 'error', 'crashed', 'unhealthy'].includes(status.toLowerCase());

let color = 8421504; // grey for in-progress
if (isSuccess) color = 65280; // green
if (isFailed) color = 16711680; // red

let emoji = '🔄';
if (isSuccess) emoji = '✅';
if (isFailed) emoji = '❌';

return [{ json: {
  service, status, version, environment, actor, url,
  emoji, color,
  timestamp: new Date().toISOString()
}}];

parameters.jsonBody:
={
  "embeds": [{
    "title": "{{ $json.emoji }} Deployment: {{ $json.service }}",
    "color": {{ $json.color }},
    "fields": [
      { "name": "Status", "value": "{{ $json.status }}", "inline": true },
      { "name": "Environment", "value": "{{ $json.environment }}", "inline": true },
      { "name": "Triggered By", "value": "{{ $json.actor }}", "inline": true },
      { "name": "Version", "value": "{{ $json.version || 'latest' }}", "inline": true },
      { "name": "URL", "value": "{{ $json.url || 'N/A' }}", "inline": true }
    ],
    "timestamp": "{{ $json.timestamp }}",
    "footer": { "text": "24HG Deployments" }
  }]
}
